/**
 * With.in MCP Auth SDK — Types
 */
export interface WithinTokenClaims {
    sub: string;
    within_network_id: string;
    within_org_domain: string;
    within_email: string;
    within_vendor_slug?: string;
    within_trial_tier?: 'subscriber' | 'standard' | 'limited';
    within_calls_remaining?: number;
    within_lead_score?: number;
    within_upgrade_url?: string;
    /** Email-mode handoff: vendor opted out of Stripe; on trial exhaustion the
     *  SDK tells the user (in the AI client) to email this address instead of
     *  surfacing a subscribe link. Mutually exclusive with within_upgrade_url. */
    within_handoff_email?: string;
    token_type: 'identity' | 'access';
    iss: string;
    aud: string | string[];
    iat: number;
    exp: number;
}
export interface AuthResult {
    authorized: boolean;
    source?: 'within' | 'vendor';
    withinClaims?: WithinTokenClaims;
    vendorPayload?: Record<string, unknown>;
    token?: string;
    error?: string;
    /** True when the user's trial calls are exhausted. The request is still authorized
     *  so the vendor can return a helpful message instead of a hard 401 block. */
    trialExhausted?: boolean;
}
/**
 * Minimal shape of the MCP server factory's return. The SDK treats it
 * opaquely and only calls .connect(transport); the vendor registers their
 * own tools on it before returning. We don't declare `_registeredTools`
 * here because the real McpServer class marks it `private` — TS would
 * refuse the assignment. The SDK introspects it via
 * `(server as any)._registeredTools` internally.
 */
export interface McpServerLike {
    registerTool: (name: string, config: any, handler: any) => unknown;
    connect: (transport: any) => Promise<void>;
}
/** Config passed to createWithinHandler. */
export interface WithinConfig {
    /** URL to the With.in JWKS endpoint (e.g. https://gateway.getwith.in/.well-known/jwks.json) */
    jwksUrl: string;
    /** The With.in auth server base URL. Used for token validation + reporting. */
    authServerUrl: string;
    /** The vendor slug registered with With.in. */
    vendorSlug: string;
    /** The protected resource URL (used in WWW-Authenticate header for 401s). */
    resourceUrl: string;
    /** The vendor's own public base URL (e.g. https://acme-invoicing.com).
     *  When set, the SDK rewrites the trial-exhausted upgrade link so it lives
     *  on the vendor's own domain instead of With.in's. The vendor's domain has
     *  reputation with MCP clients (Claude etc.) that a With.in dev tunnel does
     *  not, which stops phishing heuristics from quarantining the link. */
    vendorHostUrl?: string;
    /** Path on the vendor's host that the SDK's subscribe handler is mounted at.
     *  Defaults to '/subscribe'. */
    subscribePath?: string;
    /** Fallback sign-up URL shown to users when `within_upgrade_url` isn't on
     *  the token. Optional — With.in's token normally has this claim. */
    vendorSignupUrl?: string;
    /** Optional vendor-native token validator. If it returns non-null, the
     *  request is authorized as a subscriber without checking With.in's JWKS. */
    vendorTokenValidator?: (token: string) => Promise<Record<string, unknown> | null>;
    /** Extract the user's email from your own token payload. Enables automatic
     *  conversion tracking — when a user who previously trialed via With.in
     *  signs in with your own token, With.in marks them as a subscriber. */
    extractEmail?: (vendorPayload: Record<string, unknown>) => string | null;
    /** zod module — required for registering the network tools. Pass your own
     *  `import * as z from 'zod'` (or equivalent). Zod v4 is required. */
    zod: any;
    /** Factory that returns a new MCP server per session. The SDK calls this
     *  once per new MCP session, registers the network tools on the returned
     *  server, and drives the transport. */
    createMcpServer: () => McpServerLike;
    /** Optional: the vendor's own subscriber lookup. Called after token
     *  validation with the authenticated user's email. Return truthy to grant
     *  subscriber-tier access (no trial limits, no trial-exhausted message). */
    isSubscriber?: (email: string) => Promise<boolean> | boolean;
    /** Optional: scopes this RS advertises in its Protected Resource Metadata.
     *  Defaults to ['tools:read', 'tools:write']. */
    scopesSupported?: string[];
    /** Optional: how tokens may be sent to this RS. Defaults to ['header']. */
    bearerMethodsSupported?: ('header' | 'body' | 'query')[];
    /** Optional diagnostic logger. Called at key lifecycle events so the
     *  vendor can plug in their own logging. If omitted, nothing is logged. */
    log?: (line: string) => void;
}
/** Backwards-compat — no longer used in the new SDK. */
export interface WithinAuthOptions {
    withinJwksUrl: string;
    vendorTokenValidator?: (token: string) => Promise<Record<string, unknown> | null>;
    headerName?: string;
}
